import{j as e}from"./index-7exOWDGR.js";function r(){return e.jsxs(e.Fragment,{children:[e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:4",children:"Every Amazon DSP owner has the same Monday morning ritual: open Cortex, look at the weekly scorecard, and try to work out which driver, which route, or which day dragged the numbers. If your status moved from Fantastic Plus to Fantastic — or worse, from Fantastic to Great — you've got a week to figure out what broke and prove you can fix it."}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:10",children:"The good news: scorecards almost always slip for predictable, fixable reasons. Below is the per-metric playbook we see working with UK Amazon DSPs."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:15",children:"What the Amazon Cortex scorecard actually measures"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:16",children:"The Cortex DA scorecard rolls six core metrics into a weekly status banner (Fantastic Plus, Fantastic, Great, Fair, Poor). Each metric is a leading indicator of how well your fleet executed against Amazon's promise to the customer. Understanding them in plain English is the first step:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:21",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:22",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:23",children:"DCR (Delivery Completion Rate)"})," — the share of assigned stops that were actually completed. Misses come from undelivered packages, returns to station, and incomplete waves."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:26",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:27",children:"DPMO (Defects Per Million Opportunities)"})," — physical defects: damages, missing items, wrong addresses, lost packages. Counted per million stops, so even small absolute numbers move the metric."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:31",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:32",children:"DNR (Delivered Not Received)"})," — customer-reported claims that a package was marked delivered but never arrived. Often tied to specific drivers or specific addresses."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:35",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:36",children:"POD (Photo on Delivery)"})," — compliance with the photo-on-delivery requirement for drop-offs. Low POD scores almost always cluster around a small number of drivers."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:39",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:40",children:"CC (Contact Compliance)"})," — drivers using the Mentor app to contact customers when deliveries can't complete. Skipped contacts compound into DNR and DCR misses downstream."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:43",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:44",children:"CDF (Customer Delivery Feedback)"})," — direct customer feedback rolled up into a score. Soft signal but it correlates tightly with CC and POD."]})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:49",children:"Why scorecards drift, even when nothing has obviously gone wrong"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:50",children:`Most DSPs we talk to don't have a "bad fleet" problem. They have a visibility problem. You see the weekly scorecard on Monday — but the events that produced it happened across hundreds of stops, on ten different routes, over seven days. By the time you're trying to fix it, the people involved have forgotten the specifics.`}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:56",children:"The structural fix is to look at metrics live, per driver, mid-week — not as a summary after the fact. The tactical fixes below assume you can."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:61",children:"DCR — lift it with route-handoff discipline"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:62",children:"DCR drops happen on the routes that finish late, run out of time, or get returned partially complete. Two interventions:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:66",children:[e.jsx("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:67",children:"Track planned vs actual finish times per route. Routes that consistently finish in the red are either over-stopped or assigned to drivers who need a route swap."}),e.jsx("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:71",children:'Cut "return to station with packages" events. When a driver is on track to RTS with parcels, get them on the phone before the end of the wave — almost always you can either reroute the remaining stops or get them a one-hour extension.'})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:78",children:"DPMO — fix the upstream van check, not the downstream defect"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:79",children:"Most DPMO defects you can prevent — damaged parcels, wrong-address attempts, missing items — trace back to two events: a sloppy van load and an unchecked van. Both are upstream of dispatch."}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:83",children:"A daily van inspection with photos (yes, every day) catches the small issues that turn into customer complaints by Friday. And a pre-departure check on package counts catches the missing-item DPMO hits before the van leaves the station. The drivers who skip these checks are usually the drivers driving your DPMO."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:90",children:"DNR — investigate every claim, even when it feels unfair"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:91",children:"DNRs feel like the metric you can't control, but the patterns are obvious once you look. Claims tend to cluster around three things: specific drivers, specific addresses, and specific times of day (usually evening drops in low-light conditions). Pull the last 30 days of DNR claims, sort by driver, and the top two names will almost always be over-represented. That's where the conversation starts."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:98",children:"POD — make it visible to drivers daily, not weekly"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:99",children:"POD compliance is the easiest metric to fix because it's a behaviour, not a skill. The drivers with low POD scores almost always know exactly which photos they skipped — they just don't see the consequence until your Monday meeting. Surface every driver's personal POD score back to them daily, on their phone, and the metric moves within two weeks."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:106",children:"CC — train it as a habit, not a one-off briefing"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:107",children:"Contact Compliance is about drivers actually using the Mentor app's contact buttons when they can't complete a delivery. The fix is repetition: review CC misses in the morning huddle, the same way you review safety. After three weeks of consistent feedback, drivers internalise it."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:113",children:"CDF — the lagging indicator that confirms the rest is working"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:114",children:"Customer Delivery Feedback rises automatically when POD and CC rise. There's no separate lever for it. If the other five metrics are improving and CDF isn't, look at handover quality — are drivers leaving packages in places customers don't expect, or rushing the doorstep interaction."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:120",children:"The Monday-to-Friday review rhythm"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:121",children:"Owners who consistently hit Fantastic Plus run the same loop:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:124",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:125",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:126",children:"Monday:"})," review the previous week's scorecard with the OSM and identify the one or two metrics most at risk."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:129",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:130",children:"Tuesday–Thursday:"})," short morning huddles focused on yesterday's actual driver-level numbers, not the fleet average."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:133",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:134",children:"Friday:"})," a quick scan of the week's trajectory — escalations for any driver consistently below standard, recognition for the top performers."]})]}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:138",children:"The thing that breaks this loop, every time, is data. If your OSM is rebuilding metric tables in Excel every morning instead of running the huddle, the loop dies by Wednesday."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:143",children:"Where DSPOps fits in"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:144",children:"DSPOps connects to Amazon Cortex and pulls every scorecard metric in live, per driver and per route. Your OSM opens the dashboard, sees the three drivers most likely to drag this week's score, and runs the huddle in two minutes. Drivers see their own metrics inside the driver portal — the ones who care about being top of the leaderboard self-correct without a meeting."}),e.jsxs("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:150",children:["If you want to see what your DSP's scorecard looks like inside DSPOps, you can"," ",e.jsx("a",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:152",href:"#book-demo",className:"text-brand font-semibold hover:underline",children:"book a 20-minute demo"})," ","— we'll set up your data live during the call."]})]})}function n(){return e.jsxs(e.Fragment,{children:[e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:4",children:"If you manage a UK Amazon DSP, your Amazon Cortex DCR score is the metric that can define your entire week. A single bad day — a wave that ran over time, a batch of returns, a driver who went off-route — shows up on Monday as a percentage drop that feels impossible to trace. This guide explains exactly what DCR measures, what separates a Fantastic score from a Fair one, the most common reasons it falls, and the specific steps you can take to push it back up before the next weekly scorecard lands."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:13",children:"What DCR actually measures — and why Amazon weights it so heavily"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:14",children:"DCR stands for Delivery Completion Rate. It measures the share of your assigned stops that were actually delivered successfully during the wave. If your driver was allocated 120 stops and completed 117, their DCR for that route is 97.5%."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:19",children:"Amazon weights DCR heavily because it is the most direct proxy for customer promise fulfilment. Every stop that does not complete either generates a redelivery attempt (which costs Amazon money), a customer complaint (which increases your DNR exposure), or a returned parcel (which the customer must then chase). Across a fleet of ten drivers doing six days a week, even a 1% DCR miss compounds quickly."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:26",children:"DCR is calculated weekly across your entire DA fleet. It does not average out neatly — a single driver completing three short waves with several missed stops can pull down a fleet that is otherwise performing well. That is why understanding DCR at the individual driver and route level matters far more than watching the fleet headline figure alone."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:33",children:"What a good Amazon Cortex DCR score looks like"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:34",children:"Amazon's Cortex scoring bands work roughly as follows (exact thresholds vary by programme and region, but UK brackets align broadly with these figures):"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:38",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:39",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:40",children:"Fantastic Plus:"})," DCR at or above 98.0%"]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:42",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:43",children:"Fantastic:"})," DCR between 96.5% and 97.9%"]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:45",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:46",children:"Great:"})," DCR between 95.0% and 96.4%"]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:48",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:49",children:"Fair:"})," DCR between 90.0% and 94.9%"]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:51",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:52",children:"Poor:"})," DCR below 90.0%"]})]}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:55",children:"Most DSPs aiming for Fantastic Plus need every driver consistently above 97%. That sounds achievable until you factor in long days, Same-Day Delivery waves, bad weather, and the occasional driver who ends a shift early."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:60",children:"The target to aim for is not 96% — it is 98% and above, because that is the buffer that absorbs your worst-performing route on your worst day of the week and still keeps you in the top band. Anything below 95% starts to attract attention from your Station Operations Manager and can affect your zone and route allocation in subsequent weeks."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:67",children:"The five most common reasons DCR drops"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:68",children:"Understanding why DCR falls is the first step to fixing it. These are the five patterns seen most often across UK DSPs:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:72",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:73",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:74",children:"Waves that run over time."})," When a driver has 130 stops and a 10-hour shift, the maths do not work. Stops that cannot be completed before the wave closes automatically count against DCR. Over-loading happens when route planning does not account for realistic completion rates, traffic density, or stop complexity."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:79",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:80",children:"Returns to station with packages."})," If a driver ends the day with undelivered parcels rather than attempting every stop, those count directly against DCR. This is often a discipline issue, but it can also be a training one — drivers who do not understand the consequence of leaving stops undelivered will repeat the behaviour."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:85",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:86",children:"Failed attempts at problem addresses."})," Some addresses generate repeated failures — gated properties, businesses that close early, access codes that do not work. Each failed attempt on an address that was never going to be deliverable drags the score without the driver doing anything wrong."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:91",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:92",children:"Same-Day Delivery (SDD) wave compression."})," SDD waves have tighter time windows and less tolerance for exceptions. A driver handling both standard and SDD on the same day is more likely to leave stops incomplete because of the competing time pressure."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:96",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:97",children:"Inexperienced drivers on dense urban routes."})," New drivers in city centres take longer to locate addresses, struggle with access, and are more likely to miss difficult deliveries. Assigning newer drivers to routes with a high stop density and tight timing is a reliable way to pull DCR down."]})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:104",children:"A per-driver playbook to fix it this week"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:105",children:"DCR improvement happens at the driver level, not the fleet level. Here is the sequence that works:"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:109",children:"Pull the last four weeks of DCR data for every driver individually. Sort it lowest to highest. The bottom three or four drivers will almost always account for more than half of your DCR gap. That is where to focus first."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:114",children:"For each driver below 96%, work through these steps:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:117",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:118",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:119",children:"Identify the specific routes or waves where they missed."})," Was it the same route each time? If so, the route is likely over-stopped, not the driver."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:122",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:123",children:"Check whether incomplete stops fell at the start or end of the wave."})," ","Late-day misses suggest a time management issue. Early misses point to address-level problems."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:127",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:128",children:"Reroute or rebalance if the route itself is the problem."})," Some routes genuinely cannot be completed in the time window allocated. No amount of driver coaching fixes a structural mismatch."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:132",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:133",children:"Run a one-to-one conversation — not a group briefing."})," Drivers respond differently when they see their own score rather than the fleet average. A targeted conversation about their specific numbers lands differently from a Monday morning announcement about DCR being down."]})]}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:139",children:"Track progress daily through the week. By Thursday you will know whether the changes are working or whether a different intervention is needed before Monday's scorecard."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:144",children:"How to spot a falling DCR before the weekly scorecard lands"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:145",children:"The weekly scorecard is a lagging indicator. By Monday, the damage is already done. DSPs that consistently hit Fantastic Plus have real-time or daily visibility into the signals that predict DCR — not the score itself, but the events that produce it."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:150",children:"Indicators to watch mid-week:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:153",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:154",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:155",children:"Waves closing with packages still on the van."})," If your OSM can see at 4 pm that a driver has 15 stops remaining with 45 minutes of wave time left, intervention is still possible — a phone call, a route swap, a time extension request to the station."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:159",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:160",children:"Return-to-station (RTS) events."})," Every RTS event with packages still on board is a direct DCR miss. Each one should generate an alert the same day so it can be investigated and addressed before it happens again the next morning."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:164",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:165",children:"Incomplete-stop patterns clustering around specific drivers."})," One driver missing five stops across three days is a different problem from three drivers missing two stops each. The former needs an individual intervention; the latter probably needs a route or timing review."]})]}),e.jsxs("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:171",children:["Linking your Cortex data to a live"," ",e.jsx("a",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:173",href:"/driver-performance-tracking",children:"driver performance tracking"})," tool is what separates reactive Monday reviews from proactive Wednesday fixes. The DSPs that hold Fantastic Plus week after week are not lucky — they see the problem on Wednesday and resolve it before the wave closes."]}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:179",children:"Frequently asked questions"}),e.jsx("h3",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:181",children:"What is a good DCR score on Amazon Cortex?"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:182",children:"A DCR of 98% or above puts you in the Fantastic Plus band, which is the target for DSPs who want maximum flexibility on route awards and zone allocation. Fantastic (96.5%–97.9%) is acceptable but leaves no buffer for a difficult week. Anything below 95% (Great band or lower) starts to attract scrutiny from your Station Operations Manager and can affect future route and zone assignments."}),e.jsx("h3",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:190",children:"Why is my DCR low even when my drivers are completing their routes?"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:191",children:"DCR misses do not always mean drivers are skipping stops deliberately. Common hidden causes include waves timed too tightly so late stops close before they can be completed, Same-Day Delivery schedule pressure bleeding into standard routes, and problem addresses that generate automatic fails regardless of how many attempts are made. Check your incomplete stops at the route level rather than the fleet level to find the pattern — it is nearly always concentrated on a small number of routes or drivers."}),e.jsx("h3",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:200",children:"How often does DCR update in Amazon Cortex?"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:201",children:"Amazon Cortex updates its DA scorecard metrics weekly. The scorecard visible on Monday reflects activity from the previous week (typically Monday to Sunday). There is no live DCR figure within Cortex itself, which is why DSPs who need intra-week visibility have to pull metrics via a connected tool rather than waiting for the weekly reset. By the time you see a low score in Cortex, you are already a week behind."}),e.jsx("h3",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:209",children:"Does one driver's low DCR affect my whole fleet score?"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:210",children:"Yes. DCR is calculated across your entire DA fleet. A single driver completing three partial waves in a week can pull your fleet DCR down by 0.5–1.0 percentage points depending on fleet size. This is why per-driver visibility matters more than the headline fleet average — the fleet number hides the individual contributors."}),e.jsx("h3",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:217",children:"Can I dispute a DCR miss if the stop was undeliverable?"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:218",children:"In some cases, yes. Amazon allows exception requests for certain stop types — gated properties, incorrect addresses supplied by the customer, and customer cancellations. The process varies by station, but your Station Operations Manager is the first contact. Document the specific stop details and the reason for non-completion at the time it happens, not after the scorecard has landed — retrospective disputes are harder to support without same-day evidence."}),e.jsxs("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:227",children:["If you want daily DCR visibility without rebuilding your tracking in spreadsheets, DSPOps connects to Amazon Cortex and surfaces every driver's completion rate mid-wave — not after Monday's scorecard. It is"," ",e.jsx("a",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:231",href:"/amazon-dsp-management-software",children:"Amazon DSP management software"})," ","built specifically for UK operators, with a 14-day free trial and no credit card required."]})]})}function a(){return e.jsxs(e.Fragment,{children:[e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:4",children:"Onboarding a new driver at an Amazon DSP is never just a paperwork exercise. You are bringing someone into a role where a single missed compliance check can cost you a corrective action, and where a poorly trained first week often turns into a problem driver for months. Most DSP owners get this right eventually — but by trial and error, not by design. This guide lays out a repeatable process so that every new hire arrives at their first wave ready to perform and fully compliant."}),e.jsx("h2",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:13",children:"Before the first shift: the compliance paperwork that cannot wait"}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:14",children:"Amazon requires every DA to be cleared through its own background check process before they can deliver. That process takes time, and you cannot control the timeline — but you can make sure everything on your side is sorted before the check comes back, not after."}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:19",children:"The minimum you need in place before a new driver's first shift:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:22",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:23",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:24",children:"Right-to-work verification."})," You are legally required to check and retain a copy of the documents that prove your driver has the right to work in the UK. This is not optional and does not have a grace period. Do it before they start, not on their first day while they are standing in front of you."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:29",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:30",children:"Driving licence check."})," Check the DVLA record, not just the physical licence. You need to confirm the correct vehicle category (usually B for a standard van), verify there are no disqualifying endorsements, and note the expiry date so you can set a reminder to re-check. Photocopying a licence does not tell you its status."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:35",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:36",children:"Insurance notification."})," Add the new driver to your fleet insurance schedule. If a driver has an accident before they are added, your cover may not apply."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:39",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:40",children:"Emergency contact and employment contract."})," Basic, but often processed in the rush of a busy hiring period. Both need to be signed and filed before the first day."]})]}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:44",children:"Set up a standard checklist that your dispatcher or OSM works through for every hire, without exception. If even one item is skipped under pressure, you will eventually face the consequence."}),e.jsx("h2",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:50",children:"What Amazon checks at station — and what you should prepare for"}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:51",children:"Your new DA will go through Amazon's own station induction. What that covers varies slightly by station, but you should assume it will include: the Rabbit device setup, the Mentor app, the delivery app walkthrough, and a van safety briefing. Your job is not to duplicate what Amazon covers — it is to brief your driver on everything Amazon does not cover about working for your DSP specifically."}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:58",children:"That briefing should cover your expectations on:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:61",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:62",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:63",children:"Photo on Delivery (POD) compliance."})," New drivers often understand they need to take photos but do not understand the consequence of missing them. Walk through the POD requirement explicitly and show them what a compliant photo looks like."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:67",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:68",children:"Van inspection before every shift."})," Explain that a daily check-sheet is not a formality — it is how you document pre-existing damage and keep your fleet insurance clean. Make clear that missed inspections have consequences."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:72",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:73",children:"What to do when a delivery cannot complete."})," Many DNR claims and Contact Compliance misses come from drivers who did not know the right procedure for an undeliverable stop. Cover Contact Compliance and how to log exceptions clearly."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:77",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:78",children:"Shift start time and what late arrival means for the wave."})," New drivers often do not realise that being 20 minutes late at the station ripples through to over-stopped routes and incomplete waves."]})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:84",children:"Setting new drivers up in your systems"}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:85",children:"Before a new driver's first shift, they need to exist in every system your operation runs through — not just Amazon's. That means:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:89",children:[e.jsx("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:90",children:"Adding them to your rota software so they can be scheduled and can see their shifts in advance."}),e.jsx("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:94",children:"Creating their profile in your performance tracking tool so you can start monitoring their metrics from day one rather than scrambling for data after their first week."}),e.jsx("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:98",children:"Storing their right-to-work documents, licence details, and licence expiry date in a searchable place — not a filing cabinet and not a folder on someone's laptop."}),e.jsx("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:102",children:"Setting up a licence re-check reminder. Licence expiry typically comes around 10 years after issue. That is far enough away to feel irrelevant at onboarding, which is exactly why it gets missed."})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:109",children:"The first two weeks: building the habits that stick"}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:110",children:"The first two weeks are when a new driver's habits are formed. The drivers who become consistent performers are almost always the ones who received consistent feedback in their first fortnight — not a one-off induction and then silence until something went wrong."}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:115",children:"A simple structure that works:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:118",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:119",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:120",children:"End of day 1:"})," a brief check-in on how the wave went, any confusion about procedures, any equipment issues. Takes five minutes and catches the problems that will become habits if left unaddressed."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:124",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:125",children:"End of week 1:"})," share their actual scorecard metrics with them — POD rate, completion rate, any DNR flags. Make sure they know how to read the numbers and what they mean for their role. Drivers who see their own data early take ownership of it."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:129",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:130",children:"End of week 2:"})," a proper one-to-one. What is going well, what needs work, any route or scheduling adjustments needed. By this point you have two weeks of data to work from rather than an impression."]})]}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:135",children:"The DSPs with the lowest driver turnover are the ones where new starters feel visible and supported from the beginning. That is not about being soft on performance — it is about being clear about expectations and consistent about feedback."}),e.jsx("h2",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:141",children:"Where DSPOps fits in"}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:142",children:"DSPOps centralises the compliance and performance side of driver onboarding. Right-to-work status, licence details, and expiry reminders are stored per driver and surfaced automatically when they are coming due — so nothing gets missed because someone forgot to check a spreadsheet. New drivers appear in the performance dashboard from their first shift, so your OSM can monitor their metrics and run the week-one review with actual numbers rather than impressions."}),e.jsxs("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:150",children:["If you want to see how the onboarding and compliance workflows work inside DSPOps, you can"," ",e.jsx("a",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:152",href:"#book-demo",className:"text-brand font-semibold hover:underline",children:"book a 20-minute demo"})," ","— we will walk through your specific setup and show you what it looks like for your fleet."]})]})}const s=[{slug:"how-to-onboard-new-drivers-amazon-dsp",title:"How to onboard new drivers at an Amazon DSP",description:"A step-by-step guide to onboarding new Amazon DSP drivers in the UK — right-to-work checks, licence verification, station induction, and the two-week follow-up routine.",excerpt:"Most DSP driver problems start in week one. Here is the compliance checklist and two-week routine that turns new starters into consistent performers.",date:"2026-06-01",readingMinutes:5,Body:a},{slug:"amazon-cortex-dcr-score",title:"What is a good Amazon Cortex DCR score, and how do you improve it?",metaTitle:"Amazon Cortex DCR Score: What's Good and How to Improve It",description:"What DCR means on your Amazon Cortex scorecard, what counts as a good score, and the exact steps UK DSPs use to push it higher.",excerpt:"Your Amazon Cortex DCR score defines your week. Here's what counts as a good score, why it drops, and the per-driver playbook to fix it fast.",date:"2026-05-29",readingMinutes:7,Body:n},{slug:"improve-amazon-cortex-scorecard",title:"How to improve your Amazon Cortex scorecard",description:"A practical guide for DSP owners on lifting DCR, DPMO, DNRs, POD, CC, and CDF — week by week.",excerpt:"Every Amazon DSP owner stares at the Cortex scorecard on Monday. Here's the per-metric playbook to actually move the numbers.",date:"2026-05-18",readingMinutes:7,Body:r}];function i(t){return s.find(o=>o.slug===t)}export{s as b,i as g};
